        }
    }

    private fun ASTNode.isOnlyElementInSingleLineBlock(): Boolean {
        val prevNonWhitespaceLeaf = prevLeaf { it.elementType != WHITE_SPACE }
        val nextNonWhitespaceLeaf = nextLeaf { it.elementType != WHITE_SPACE }
        return prevNonWhitespaceLeaf?.elementType == LBRACE &&
            nextNonWhitespaceLeaf?.elementType == RBRACE &&
            !textContains('\n') &&
            !hasNewLineInClosedRange(prevNonWhitespaceLeaf, nextNonWhitespaceLeaf)
    }

    private fun isNonIndentLeafOnSameLine(it: ASTNode) = it.elementType != WHITE_SPACE || !it.textContains('\n')
